import{_ as e,c as s,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"v1.0.0-v1.0.1: 初始版本發布 | opencode-mystatus","description":"瞭解 opencode-mystatus v1.0.0 初始版本的新功能，包括 OpenAI、智證 AI、Google Cloud 額度查詢、可視化進度條、多語言支援，以及 v1.0.1 的斜線指令修復。","frontmatter":{"title":"v1.0.0-v1.0.1: 初始版本發布 | opencode-mystatus","sidebarTitle":"v1.0.0-v1.0.1","description":"瞭解 opencode-mystatus v1.0.0 初始版本的新功能，包括 OpenAI、智證 AI、Google Cloud 額度查詢、可視化進度條、多語言支援，以及 v1.0.1 的斜線指令修復。","subtitle":"v1.0.0-v1.0.1: 初始版本發布","tags":["版本","更新日誌","v1.0.0","v1.0.1"],"order":2},"headers":[],"relativePath":"zh-tw/vbgate/opencode-mystatus/changelog/v100-v101/index.md","filePath":"zh-tw/vbgate/opencode-mystatus/changelog/v100-v101/index.md"}'),n={name:"zh-tw/vbgate/opencode-mystatus/changelog/v100-v101/index.md"};function o(l,a,d,p,h,r){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="v1-0-0-v1-0-1-初始版本發布和斜線指令修復" tabindex="-1">v1.0.0 - v1.0.1：初始版本發布和斜線指令修復 <a class="header-anchor" href="#v1-0-0-v1-0-1-初始版本發布和斜線指令修復" aria-label="Permalink to &quot;v1.0.0 - v1.0.1：初始版本發布和斜線指令修復&quot;">​</a></h1><h2 id="版本概述" tabindex="-1">版本概述 <a class="header-anchor" href="#版本概述" aria-label="Permalink to &quot;版本概述&quot;">​</a></h2><p><strong>v1.0.0</strong>（2026-01-11）是 opencode-mystatus 的初始版本，帶來了多平台額度查詢的核心功能。</p><p><strong>v1.0.1</strong>（2026-01-11）立即跟進，修復了斜線指令支援的關鍵問題。</p><hr><h2 id="v1-0-1-斜線指令修復" tabindex="-1">v1.0.1 - 斜線指令修復 <a class="header-anchor" href="#v1-0-1-斜線指令修復" aria-label="Permalink to &quot;v1.0.1 - 斜線指令修復&quot;">​</a></h2><h3 id="修復問題" tabindex="-1">修復問題 <a class="header-anchor" href="#修復問題" aria-label="Permalink to &quot;修復問題&quot;">​</a></h3><p><strong>包含 <code>command/</code> 目錄到 npm 套件</strong></p><ul><li><strong>問題描述</strong>：v1.0.0 發布後，發現斜線指令 <code>/mystatus</code> 無法正常工作</li><li><strong>原因分析</strong>：npm 打包時遺漏了 <code>command/</code> 目錄，導致 OpenCode 無法識別斜線指令</li><li><strong>修復方案</strong>：更新 <code>package.json</code> 的 <code>files</code> 欄位，確保 <code>command/</code> 目錄被包含在發布套件中</li><li><strong>影響範圍</strong>：僅影響透過 npm 安裝的使用者，手動安裝不受影響</li></ul><h3 id="升級建議" tabindex="-1">升級建議 <a class="header-anchor" href="#升級建議" aria-label="Permalink to &quot;升級建議&quot;">​</a></h3><p>如果你已經安裝了 v1.0.0，建議立即升級到 v1.0.1 以獲得完整的斜線指令支援：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 升級到最新版本</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><hr><h2 id="v1-0-0-初始版本發布" tabindex="-1">v1.0.0 - 初始版本發布 <a class="header-anchor" href="#v1-0-0-初始版本發布" aria-label="Permalink to &quot;v1.0.0 - 初始版本發布&quot;">​</a></h2><h3 id="新增功能" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能" aria-label="Permalink to &quot;新增功能&quot;">​</a></h3><p><strong>1. 多平台額度查詢</strong></p><p>支援一鍵查詢以下平台的額度使用情況：</p><table tabindex="0"><thead><tr><th>平台</th><th>支援的訂閱類型</th><th>額度類型</th></tr></thead><tbody><tr><td>OpenAI</td><td>Plus/Team/Pro</td><td>3 小時限額、24 小時限額</td></tr><tr><td>智證 AI</td><td>Coding Plan</td><td>5 小時 Token 限額、MCP 月度配額</td></tr><tr><td>Google Cloud</td><td>Antigravity</td><td>G3 Pro、G3 Image、G3 Flash、Claude</td></tr></tbody></table><p><strong>2. 可視化進度條</strong></p><p>直觀展示額度使用情況：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OpenAI (user@example.com)</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━ 75%</span></span>
<span class="line"><span>已用 750 / 1000 次請求</span></span></code></pre></div><p><strong>3. 多語言支援</strong></p><ul><li>中文（繁體）</li><li>英文</li></ul><p>語言自動偵測，無需手動切換。</p><p><strong>4. API Key 安全脫敏</strong></p><p>所有敏感資訊（API Key、OAuth Token）自動脫敏顯示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>智證 AI (zhipuai-coding-plan)</span></span>
<span class="line"><span>API Key: sk-a1b2****xyz</span></span></code></pre></div><hr><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><h3 id="斜線指令-推薦" tabindex="-1">斜線指令（推薦） <a class="header-anchor" href="#斜線指令-推薦" aria-label="Permalink to &quot;斜線指令（推薦）&quot;">​</a></h3><p>在 OpenCode 中輸入：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><h3 id="自然語言" tabindex="-1">自然語言 <a class="header-anchor" href="#自然語言" aria-label="Permalink to &quot;自然語言&quot;">​</a></h3><p>你也可以用自然語言詢問：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查看我的所有 AI 平台額度</span></span></code></pre></div><hr><h2 id="升級指南" tabindex="-1">升級指南 <a class="header-anchor" href="#升級指南" aria-label="Permalink to &quot;升級指南&quot;">​</a></h2><h3 id="從-v1-0-0-升級到-v1-0-1" tabindex="-1">從 v1.0.0 升級到 v1.0.1 <a class="header-anchor" href="#從-v1-0-0-升級到-v1-0-1" aria-label="Permalink to &quot;從 v1.0.0 升級到 v1.0.1&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><p>升級後，重新啟動 OpenCode 即可使用斜線指令 <code>/mystatus</code>。</p><h3 id="首次安裝" tabindex="-1">首次安裝 <a class="header-anchor" href="#首次安裝" aria-label="Permalink to &quot;首次安裝&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @vbgate/opencode-mystatus</span></span></code></pre></div><p>安裝完成後，在 OpenCode 中輸入 <code>/mystatus</code> 即可查詢所有平台的額度。</p><hr><h2 id="已知限制" tabindex="-1">已知限制 <a class="header-anchor" href="#已知限制" aria-label="Permalink to &quot;已知限制&quot;">​</a></h2><ul><li>v1.0.0 不支援 GitHub Copilot（v1.2.0 新增）</li><li>v1.0.0 不支援 Z.ai（v1.1.0 新增）</li></ul><p>如需使用這些功能，請升級到最新版本。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>查看 <a href="./../v120-v124/">v1.2.0 - v1.2.4 更新日誌</a> 瞭解 GitHub Copilot 支援等新功能。</p>`,50)])])}const v=e(n,[["render",o]]);export{u as __pageData,v as default};
